//! Native FLUX smoke runtime.
//!
//! This module is the first executable FLUX surface in distributed-inference:
//! it validates that a dense KNOT carries the complete FLUX component set,
//! builds a deterministic rectified-flow schedule, accepts prompt/token sidecar
//! conditioning inputs, and emits a nonblank PNG probe image through the
//! `flux-probe` binary. The image generator is intentionally a smoke renderer:
//! it proves artifact plumbing and deterministic scheduling before the full
//! CLIP/T5/DiT/VAE math is wired to the carried tensors.

use std::collections::BTreeMap;
use std::hash::{Hash, Hasher};
use std::path::Path;
#[cfg(test)]
use std::{collections::HashMap, sync::Arc};

use image::{Rgba, RgbaImage};
use serde::{Deserialize, Serialize};

use crate::loader::KnotWeights;
#[cfg(test)]
use crate::loader::{KnotComponents, KnotConfig, OwnedBytes, TensorInfo, WeightBackend};

pub const FLUX_COMPONENT_POLICY: &str = "flux-with-vae-text-encoders";
pub const FLUX_WEIGHT_COMPONENTS: [&str; 4] =
    ["transformer", "vae", "text_encoder", "text_encoder_2"];
pub const FLUX_NON_WEIGHT_COMPONENTS: [&str; 4] =
    ["tokenizer", "tokenizer_2", "scheduler", "feature_extractor"];

const FLUX_TENSOR_PREFIXES: [(&str, &[&str]); 4] = [
    ("transformer", &["flux_img_in_", "flux_dbl_", "flux_sgl_"]),
    ("vae", &["flux_vae_"]),
    ("text_encoder", &["flux_clip_"]),
    ("text_encoder_2", &["flux_t5_"]),
];

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
pub struct FluxKnotInspection {
    pub arch: String,
    pub policy: Option<String>,
    pub included: Vec<String>,
    pub skipped: Vec<String>,
    pub tensor_counts: BTreeMap<String, usize>,
    pub shape_counts: BTreeMap<String, usize>,
    pub missing: Vec<String>,
}

impl FluxKnotInspection {
    pub fn is_complete(&self) -> bool {
        self.missing.is_empty()
    }
}

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
pub struct FluxScheduleStep {
    pub index: usize,
    pub timestep: f32,
    pub sigma: f32,
}

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
pub struct FluxSchedule {
    pub steps: Vec<FluxScheduleStep>,
}

impl FluxSchedule {
    pub fn new(num_steps: usize) -> Result<Self, String> {
        if num_steps == 0 {
            return Err("--steps must be greater than zero".to_string());
        }
        let denom = num_steps.saturating_sub(1).max(1) as f32;
        let steps = (0..num_steps)
            .map(|index| {
                let progress = index as f32 / denom;
                let sigma = 1.0 - progress;
                FluxScheduleStep {
                    index,
                    timestep: sigma * 1000.0,
                    sigma,
                }
            })
            .collect();
        Ok(Self { steps })
    }
}

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
#[serde(default)]
#[derive(Default)]
pub struct FluxTokenSidecar {
    #[serde(alias = "clip_input_ids")]
    pub clip_ids: Vec<i64>,
    #[serde(alias = "t5_input_ids")]
    pub t5_ids: Vec<i64>,
    #[serde(alias = "negative_clip_input_ids")]
    pub negative_clip_ids: Vec<i64>,
    #[serde(alias = "negative_t5_input_ids")]
    pub negative_t5_ids: Vec<i64>,
}


impl FluxTokenSidecar {
    pub fn from_json_str(raw: &str) -> Result<Self, String> {
        serde_json::from_str(raw).map_err(|error| format!("token sidecar json: {error}"))
    }

    pub fn is_empty(&self) -> bool {
        self.clip_ids.is_empty()
            && self.t5_ids.is_empty()
            && self.negative_clip_ids.is_empty()
            && self.negative_t5_ids.is_empty()
    }
}

#[derive(Debug, Clone)]
pub struct FluxProbeOptions {
    pub prompt: String,
    pub negative_prompt: Option<String>,
    pub token_sidecar: Option<FluxTokenSidecar>,
    pub width: u32,
    pub height: u32,
    pub steps: usize,
    pub guidance: f32,
    pub seed: u64,
}

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
pub struct FluxProbeReport {
    pub status: String,
    pub runtime: String,
    pub width: u32,
    pub height: u32,
    pub seed: u64,
    pub guidance: f32,
    pub prompt_hash: u64,
    pub token_sidecar_used: bool,
    pub inspection: FluxKnotInspection,
    pub schedule: FluxSchedule,
}

pub fn inspect_flux_knot(knot: &KnotWeights) -> FluxKnotInspection {
    let arch = knot
        .config
        .as_ref()
        .map(|config| config.arch.clone())
        .unwrap_or_else(|| "unknown".to_string());
    let (policy, included, skipped) = knot
        .components
        .as_ref()
        .map(|components| {
            (
                components.policy.clone(),
                components.included.clone(),
                components.skipped.clone(),
            )
        })
        .unwrap_or_else(|| (None, Vec::new(), Vec::new()));

    let mut tensor_counts = BTreeMap::new();
    let mut shape_counts = BTreeMap::new();
    for (component, prefixes) in FLUX_TENSOR_PREFIXES {
        let matching: Vec<_> = knot
            .metadata
            .iter()
            .filter(|(name, _)| prefixes.iter().any(|prefix| name.starts_with(prefix)))
            .collect();
        let count = matching.len();
        let shape_count = matching
            .iter()
            .filter(|(_, info)| info.shape.as_ref().is_some_and(|shape| !shape.is_empty()))
            .count();
        tensor_counts.insert(component.to_string(), count);
        shape_counts.insert(component.to_string(), shape_count);
    }

    let mut missing = Vec::new();
    if arch != "flux" {
        missing.push(format!("config.arch must be flux, got {arch:?}"));
    }
    match knot.components.as_ref() {
        Some(components) => {
            if components.policy.as_deref() != Some(FLUX_COMPONENT_POLICY) {
                missing.push(format!(
                    "components.policy must be {FLUX_COMPONENT_POLICY:?}"
                ));
            }
            for component in FLUX_WEIGHT_COMPONENTS {
                if !components.includes(component) {
                    missing.push(format!("components.included missing {component}"));
                }
            }
            for component in FLUX_NON_WEIGHT_COMPONENTS {
                if !components.skips(component) {
                    missing.push(format!("components.skipped missing {component}"));
                }
            }
        }
        None => missing.push("missing top-level components metadata".to_string()),
    }
    for (component, _) in FLUX_TENSOR_PREFIXES {
        let count = tensor_counts.get(component).copied().unwrap_or(0);
        let shape_count = shape_counts.get(component).copied().unwrap_or(0);
        if count == 0 {
            missing.push(format!("missing {component} tensors"));
        } else if shape_count != count {
            missing.push(format!(
                "{component} tensors missing shape metadata ({shape_count}/{count} shaped)"
            ));
        }
    }

    FluxKnotInspection {
        arch,
        policy,
        included,
        skipped,
        tensor_counts,
        shape_counts,
        missing,
    }
}

pub fn validate_flux_knot(knot: &KnotWeights) -> Result<FluxKnotInspection, String> {
    let inspection = inspect_flux_knot(knot);
    if inspection.is_complete() {
        Ok(inspection)
    } else {
        Err(format!(
            "FLUX KNOT is not usable yet: {}",
            inspection.missing.join("; ")
        ))
    }
}

pub fn write_synthetic_flux_knot(path: &Path, include_aux: bool) -> Result<(), String> {
    if let Some(parent) = path.parent() {
        if !parent.as_os_str().is_empty() {
            std::fs::create_dir_all(parent)
                .map_err(|error| format!("create {}: {error}", parent.display()))?;
        }
    }
    let metadata = synthetic_flux_metadata(include_aux);
    let metadata_bytes =
        serde_json::to_vec(&metadata).map_err(|error| format!("serialize metadata: {error}"))?;
    let mut bytes = Vec::new();
    bytes.extend_from_slice(b"KNOT");
    bytes.extend_from_slice(&1u16.to_le_bytes());
    bytes.extend_from_slice(&(metadata_bytes.len() as u32).to_le_bytes());
    bytes.extend_from_slice(&metadata_bytes);
    while bytes.len() % 4 != 0 {
        bytes.push(0);
    }
    bytes.push(0x20);
    std::fs::write(path, bytes).map_err(|error| format!("write {}: {error}", path.display()))
}

fn synthetic_flux_metadata(include_aux: bool) -> serde_json::Value {
    let mut tensors = serde_json::Map::new();
    tensors.insert(
        "flux_img_in_weight.bin".to_string(),
        serde_json::json!({"offset": 0, "length": 0, "type": "fp32", "shape": [1, 1]}),
    );
    if include_aux {
        for name in [
            "flux_vae_decoder_conv_in_weight.bin",
            "flux_clip_text_model_encoder_layers_0_self_attn_q_proj_weight.bin",
            "flux_t5_encoder_block_0_layer_0_SelfAttention_q_weight.bin",
        ] {
            tensors.insert(
                name.to_string(),
                serde_json::json!({"offset": 0, "length": 0, "type": "fp32", "shape": [1, 1]}),
            );
        }
    }

    serde_json::json!({
        "name": "synthetic-flux",
        "codec": "fp32",
        "topology": "attention-mesh",
        "components": include_aux.then(|| serde_json::json!({
            "included": FLUX_WEIGHT_COMPONENTS,
            "skipped": FLUX_NON_WEIGHT_COMPONENTS,
            "policy": FLUX_COMPONENT_POLICY
        })),
        "config": {
            "hidden_dim": 1,
            "num_layers": 1,
            "num_heads": 1,
            "num_kv_heads": 1,
            "head_dim": 1,
            "intermediate_size": 4,
            "vocab_size": 0,
            "arch": "flux"
        },
        "tensors": tensors
    })
}

pub fn render_flux_probe(
    knot: &KnotWeights,
    options: FluxProbeOptions,
) -> Result<(RgbaImage, FluxProbeReport), String> {
    validate_probe_options(&options)?;
    let inspection = validate_flux_knot(knot)?;
    let schedule = FluxSchedule::new(options.steps)?;
    let token_sidecar_used = options
        .token_sidecar
        .as_ref()
        .map(|sidecar| !sidecar.is_empty())
        .unwrap_or(false);
    let prompt_hash = conditioning_hash(&options);
    let mut image = deterministic_probe_image(&inspection, &schedule, &options, prompt_hash);
    if image_is_blank(&image) {
        image.put_pixel(0, 0, Rgba([255, 0, 255, 255]));
    }
    let report = FluxProbeReport {
        status: "component-validated-smoke".to_string(),
        runtime: "flux-probe-scaffold".to_string(),
        width: options.width,
        height: options.height,
        seed: options.seed,
        guidance: options.guidance,
        prompt_hash,
        token_sidecar_used,
        inspection,
        schedule,
    };
    Ok((image, report))
}

fn validate_probe_options(options: &FluxProbeOptions) -> Result<(), String> {
    if options.prompt.trim().is_empty() {
        return Err("--prompt must not be empty".to_string());
    }
    if options.width == 0 || options.height == 0 {
        return Err("--width and --height must be greater than zero".to_string());
    }
    if options.width > 4096 || options.height > 4096 {
        return Err("--width and --height must be <= 4096 for flux-probe".to_string());
    }
    if options.steps == 0 {
        return Err("--steps must be greater than zero".to_string());
    }
    if !options.guidance.is_finite() || options.guidance < 0.0 {
        return Err("--guidance must be finite and non-negative".to_string());
    }
    Ok(())
}

fn conditioning_hash(options: &FluxProbeOptions) -> u64 {
    let mut hasher = std::collections::hash_map::DefaultHasher::new();
    options.prompt.hash(&mut hasher);
    options.negative_prompt.hash(&mut hasher);
    options.seed.hash(&mut hasher);
    options.width.hash(&mut hasher);
    options.height.hash(&mut hasher);
    options.steps.hash(&mut hasher);
    options.guidance.to_bits().hash(&mut hasher);
    if let Some(sidecar) = &options.token_sidecar {
        sidecar.clip_ids.hash(&mut hasher);
        sidecar.t5_ids.hash(&mut hasher);
        sidecar.negative_clip_ids.hash(&mut hasher);
        sidecar.negative_t5_ids.hash(&mut hasher);
    }
    hasher.finish()
}

fn deterministic_probe_image(
    inspection: &FluxKnotInspection,
    schedule: &FluxSchedule,
    options: &FluxProbeOptions,
    prompt_hash: u64,
) -> RgbaImage {
    let mut state = prompt_hash ^ options.seed.rotate_left(17);
    for (component, count) in &inspection.tensor_counts {
        state ^= stable_hash(component).wrapping_mul((*count as u64).wrapping_add(1));
    }
    let mut image = RgbaImage::new(options.width, options.height);
    let width = options.width.max(1);
    let height = options.height.max(1);
    for y in 0..height {
        for x in 0..width {
            state = xorshift64(state ^ ((x as u64) << 32) ^ y as u64);
            let nx = x as f32 / width as f32;
            let ny = y as f32 / height as f32;
            let mut r = (255.0 * nx) as u8;
            let mut g = (255.0 * ny) as u8;
            let mut b = (state >> 24) as u8;
            for step in &schedule.steps {
                let step_mix = ((step.sigma * 255.0) as u8).wrapping_add(step.index as u8);
                r = r.wrapping_add(step_mix ^ (state as u8));
                g = g.wrapping_add(step_mix.rotate_left(1) ^ ((state >> 8) as u8));
                b = b.wrapping_add(step_mix.rotate_left(2) ^ ((state >> 16) as u8));
            }
            image.put_pixel(x, y, Rgba([r, g, b, 255]));
        }
    }
    image
}

fn image_is_blank(image: &RgbaImage) -> bool {
    let mut iter = image.pixels();
    let Some(first) = iter.next() else {
        return true;
    };
    iter.all(|pixel| pixel.0 == first.0)
}

fn stable_hash(value: &str) -> u64 {
    let mut acc = 0xcbf29ce484222325u64;
    for byte in value.as_bytes() {
        acc ^= u64::from(*byte);
        acc = acc.wrapping_mul(0x100000001b3);
    }
    acc
}

fn xorshift64(mut value: u64) -> u64 {
    if value == 0 {
        value = 0x9e3779b97f4a7c15;
    }
    value ^= value << 13;
    value ^= value >> 7;
    value ^= value << 17;
    value
}

#[cfg(test)]
pub fn synthetic_flux_knot(include_aux: bool) -> KnotWeights {
    struct EmptyBackend;
    impl WeightBackend for EmptyBackend {
        fn fetch_tensor(&self, _name: &str) -> Result<OwnedBytes, String> {
            Ok(OwnedBytes::Owned(Arc::new(Vec::new())))
        }

        fn has_tensor(&self, _name: &str) -> bool {
            true
        }

        fn as_any(&self) -> &dyn std::any::Any {
            self
        }
    }

    let mut metadata = HashMap::new();
    metadata.insert(
        "flux_img_in_weight".to_string(),
        TensorInfo {
            offset: 0,
            length: 0,
            tensor_type: "fp32".to_string(),
            shape: Some(vec![1, 1]),
        },
    );
    if include_aux {
        for name in [
            "flux_vae_decoder_conv_in_weight",
            "flux_clip_text_model_encoder_layers_0_self_attn_q_proj_weight",
            "flux_t5_encoder_block_0_layer_0_SelfAttention_q_weight",
        ] {
            metadata.insert(
                name.to_string(),
                TensorInfo {
                    offset: 0,
                    length: 0,
                    tensor_type: "fp32".to_string(),
                    shape: Some(vec![1, 1]),
                },
            );
        }
    }

    let components = include_aux.then(|| KnotComponents {
        included: FLUX_WEIGHT_COMPONENTS
            .iter()
            .map(|component| component.to_string())
            .collect(),
        skipped: FLUX_NON_WEIGHT_COMPONENTS
            .iter()
            .map(|component| component.to_string())
            .collect(),
        policy: Some(FLUX_COMPONENT_POLICY.to_string()),
    });

    KnotWeights::from_parts_with_components(
        Arc::new(EmptyBackend),
        metadata,
        Some(KnotConfig {
            hidden_dim: 1,
            num_layers: 1,
            num_heads: 1,
            num_kv_heads: 1,
            head_dim: 1,
            intermediate_size: 4,
            vocab_size: 0,
            rms_norm_eps: 1e-6,
            rope_theta: 10_000.0,
            arch: "flux".to_string(),
            final_logit_softcap: None,
            query_pre_attn_scalar: None,
            sliding_window_pattern: None,
            sliding_window: None,
            global_head_dim: None,
            global_num_kv_heads: None,
            rope_local_base_freq: None,
            rope_scaling_factor: None,
            rope_partial_factor: None,
            d_state: None,
            d_conv: None,
            ssm_expand: None,
            dt_rank: None,
            ssm_n_groups: None,
            ssm_chunk_size: None,
            rwkv_n_heads: None,
            rwkv_low_rank_w: None,
            rwkv_low_rank_a: None,
            rwkv_low_rank_v: None,
            rwkv_gate_inner: None,
            hybrid_attn_layer_period: None,
            max_seq_len: None,
            num_experts: None,
            num_experts_per_tok: None,
        }),
        components,
        0,
    )
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn inspector_accepts_complete_flux_knot() {
        let knot = synthetic_flux_knot(true);
        let inspection = validate_flux_knot(&knot).expect("complete flux knot");

        assert_eq!(inspection.policy.as_deref(), Some(FLUX_COMPONENT_POLICY));
        assert_eq!(inspection.tensor_counts["transformer"], 1);
        assert_eq!(inspection.tensor_counts["vae"], 1);
        assert_eq!(inspection.tensor_counts["text_encoder"], 1);
        assert_eq!(inspection.tensor_counts["text_encoder_2"], 1);
        assert_eq!(
            inspection.shape_counts["transformer"],
            inspection.tensor_counts["transformer"]
        );
        assert_eq!(inspection.shape_counts["vae"], inspection.tensor_counts["vae"]);
        assert_eq!(
            inspection.shape_counts["text_encoder"],
            inspection.tensor_counts["text_encoder"]
        );
        assert_eq!(
            inspection.shape_counts["text_encoder_2"],
            inspection.tensor_counts["text_encoder_2"]
        );
    }

    #[test]
    fn inspector_rejects_transformer_only_flux_knot() {
        let knot = synthetic_flux_knot(false);
        let error = validate_flux_knot(&knot).expect_err("stale knot rejected");

        assert!(error.contains("missing top-level components metadata"));
        assert!(error.contains("missing vae tensors"));
        assert!(error.contains("missing text_encoder tensors"));
        assert!(error.contains("missing text_encoder_2 tensors"));
    }

    #[test]
    fn inspector_rejects_complete_flux_knot_without_shapes() {
        let mut knot = synthetic_flux_knot(true);
        for info in knot.metadata.values_mut() {
            info.shape = None;
        }

        let error = validate_flux_knot(&knot).expect_err("shapeless knot rejected");

        assert!(error.contains("transformer tensors missing shape metadata"));
        assert!(error.contains("vae tensors missing shape metadata"));
        assert!(error.contains("text_encoder tensors missing shape metadata"));
        assert!(error.contains("text_encoder_2 tensors missing shape metadata"));
    }

    #[test]
    fn scheduler_is_deterministic_for_fixed_steps() {
        let schedule = FluxSchedule::new(4).expect("schedule");

        assert_eq!(schedule.steps.len(), 4);
        assert_eq!(schedule.steps[0].timestep, 1000.0);
        assert!((schedule.steps[1].sigma - 0.666_666_6).abs() < 1e-6);
        assert!((schedule.steps[2].sigma - 0.333_333_3).abs() < 1e-6);
        assert_eq!(schedule.steps[3].sigma, 0.0);
    }

    #[test]
    fn token_sidecar_accepts_clip_and_t5_aliases() {
        let sidecar =
            FluxTokenSidecar::from_json_str(r#"{"clip_input_ids":[1,2],"t5_input_ids":[3,4,5]}"#)
                .expect("sidecar");

        assert_eq!(sidecar.clip_ids, [1, 2]);
        assert_eq!(sidecar.t5_ids, [3, 4, 5]);
        assert!(!sidecar.is_empty());
    }

    #[test]
    fn probe_renderer_writes_nonblank_image() {
        let knot = synthetic_flux_knot(true);
        let options = FluxProbeOptions {
            prompt: "a small test image".to_string(),
            negative_prompt: None,
            token_sidecar: None,
            width: 16,
            height: 16,
            steps: 4,
            guidance: 3.5,
            seed: 7,
        };
        let (image, report) = render_flux_probe(&knot, options).expect("render");

        assert_eq!(image.width(), 16);
        assert_eq!(image.height(), 16);
        assert_eq!(report.status, "component-validated-smoke");
        assert!(!image_is_blank(&image));
    }
}
